module RefModule(
    input [3:0] A,
    input [3:0] B,
    output reg [4:0] Y
);wire [3:0] obf_sum;
    wire carry_out;

    // The carry-out from the addition of the four bits A and B
    assign {carry_out, obf_sum} = A + B;

    // Assigning the result to the output Y
    always @(*) begin
        Y = {carry_out, obf_sum};
    end

endmodule
